import { useState, useEffect } from 'react';
import { getAdversarialProbe } from '../api';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ReferenceArea } from 'recharts';
import { GitMerge, Play, Activity, ShieldAlert, CheckCircle } from 'lucide-react';

export default function AdversarialProbe() {
  const [form, setForm] = useState({ user_id: 2, amount: 8000, hour: 1, location: 'Dubai', merchant: 'LuxuryMall' });
  const [results, setResults] = useState(null);
  const [animatingIdx, setAnimatingIdx] = useState(0);
  const [running, setRunning] = useState(false);

  const runProbe = async () => {
    setRunning(true);
    setResults(null);
    setAnimatingIdx(0);
    try {
      // Mock D string
      const d = new Date(); d.setHours(form.hour);
      const payload = { ...form, timestamp: d.toISOString() };

      const res = await getAdversarialProbe(payload);
      setResults(res.probe_results);

      // Animate line chart
      let idx = 0;
      const int = setInterval(() => {
        idx++;
        setAnimatingIdx(idx);
        if (idx >= res.probe_results.length) clearInterval(int);
      }, 800);

    } catch (e) {
      console.error(e);
    } finally {
      setRunning(false);
    }
  };

  const getBadgeStyle = (d) => {
    if (d === 'APPROVE') return 'bg-decision-approve/20 text-decision-approve';
    if (d === 'WARN') return 'bg-decision-warn/20 text-decision-warn';
    if (d === 'DELAY') return 'bg-decision-delay/20 text-decision-delay';
    if (d === 'BLOCK') return 'bg-decision-block/20 text-decision-block';
    return '';
  };

  return (
    <div className="space-y-6 max-w-5xl mx-auto">
      <div className="flex justify-between items-center border-b border-border pb-4">
        <div>
          <h1 className="text-3xl font-bold flex items-center gap-2"><GitMerge className="text-primary"/> Adversarial Probe</h1>
          <p className="text-secondary mt-1 tracking-wider uppercase text-xs">Simulated attack mutation modeling</p>
        </div>
      </div>

      <div className="grid grid-cols-5 gap-6">
        <div className="col-span-2 space-y-4">
           <div className="card-finguard">
             <h2 className="text-sm font-bold border-b border-border pb-2 mb-4">Base Transaction Trajectory</h2>

             <div className="space-y-4 text-sm">
               <div>
                 <label className="block text-secondary mb-1">Target User ID</label>
                 <select value={form.user_id} onChange={e => setForm({...form, user_id: parseInt(e.target.value)})}
                    className="w-full bg-background border border-border rounded p-2 text-primary focus:outline-none focus:border-decision-block">
                    <option value="1">User 1 (Aman - Standard Profile)</option>
                    <option value="2">User 2 (Riya - High Range Profile)</option>
                    <option value="3">User 3 (Kabir - Irregular Profile)</option>
                 </select>
               </div>
               <div>
                 <label className="block text-secondary mb-1">Injection Amount (Γé╣)</label>
                 <input type="number" value={form.amount} onChange={e => setForm({...form, amount: parseFloat(e.target.value)})}
                    className="w-full bg-background border border-border rounded p-2 text-primary font-mono focus:outline-none focus:border-decision-block" />
               </div>
               <div className="flex gap-2">
                 <div className="flex-1">
                   <label className="block text-secondary mb-1">Hour</label>
                   <input type="number" value={form.hour} onChange={e => setForm({...form, hour: parseInt(e.target.value)})}
                      className="w-full bg-background border border-border rounded p-2 text-primary text-center focus:outline-none focus:border-decision-block" />
                 </div>
                 <div className="flex-[2]">
                   <label className="block text-secondary mb-1">Location Context</label>
                   <input type="text" value={form.location} onChange={e => setForm({...form, location: e.target.value})}
                      className="w-full bg-background border border-border rounded p-2 text-primary focus:outline-none focus:border-decision-block" />
                 </div>
               </div>
             </div>

             <button onClick={runProbe} disabled={running} className="w-full mt-6 bg-decision-block/10 hover:bg-decision-block/20 text-decision-block border border-decision-block/50 font-bold py-3 px-4 rounded flex items-center justify-center gap-2 transition-colors">
               {running ? <Activity className="w-5 h-5 animate-spin"/> : <Play className="w-5 h-5"/>}
               {running ? 'Fuzzing...' : 'Init Mutation Sequence'}
             </button>
           </div>

           <div className="card-finguard p-4 bg-muted/10 border-dashed border-2 text-xs text-secondary leading-relaxed">
             The adversarial probe applies synthetic data mutations against the live ML manifold. It simulates attacker techniques (velocities, location hopping, amount scaling) sequentially, proving real-time barrier elasticity under dynamic load.
           </div>
        </div>

        <div className="col-span-3">
           {!results ? (
             <div className="card-finguard h-[500px] flex flex-col justify-center items-center text-center text-secondary p-8">
               <ShieldAlert className="w-16 h-16 opacity-20 mb-4 text-decision-block" />
               <p>Awaiting probe parameters. Configure payload and initialize mutation sequence.</p>
             </div>
           ) : (
             <div className="space-y-4 animate-in fade-in slide-in-from-right-4">
               <div className="card-finguard h-[300px]">
                 <h3 className="text-sm font-bold border-b border-border pb-2 mb-2">Sequence Risk Trajectory</h3>
                 <ResponsiveContainer width="100%" height="90%">
                   <LineChart lineData={results} data={results.slice(0, animatingIdx)} margin={{top: 10, right: 10, left: -20, bottom: 5}}>
                     <XAxis dataKey="step" tick={{fontSize: 10, fill: '#8b949e'}} />
                     <YAxis domain={[0, 130]} tick={{fontSize: 10, fill: '#8b949e'}} />
                     <Tooltip contentStyle={{backgroundColor: '#161b22', borderColor: '#21262d'}} cursor={{stroke: '#21262d'}}/>
                     <ReferenceArea y1={75} y2={130} fill="#f85149" fillOpacity={0.1} />
                     <ReferenceArea y1={55} y2={75} fill="#f0883e" fillOpacity={0.1} />
                     <ReferenceArea y1={0} y2={55} fill="#3fb950" fillOpacity={0.1} />
                     <Line type="monotone" dataKey="risk_score" stroke="#58a6ff" strokeWidth={3} dot={{fill: '#0d1117', stroke: '#58a6ff', strokeWidth: 2, r: 4}} isAnimationActive={true}/>
                   </LineChart>
                 </ResponsiveContainer>
               </div>

               <div className="card-finguard">
                 <table className="w-full text-left text-sm whitespace-nowrap">
                   <thead className="bg-background text-secondary">
                     <tr>
                       <th className="p-3 font-medium">Mutation Step</th>
                       <th className="p-3 font-medium text-right">Risk Force</th>
                       <th className="p-3 font-medium">Decision Vector</th>
                     </tr>
                   </thead>
                   <tbody className="divide-y divide-border/50">
                     {results.slice(0, animatingIdx).map((r, i) => (
                       <tr key={i} className="animate-in slide-in-from-left-2">
                         <td className="p-3 font-mono text-primary">{r.step}</td>
                         <td className="p-3 text-right">
                           <span className="font-bold flex items-center justify-end gap-2">{Math.round(r.risk_score)}</span>
                         </td>
                         <td className="p-3">
                           <span className={`px-2 py-1 rounded text-xs font-bold ${getBadgeStyle(r.decision)}`}>
                             {r.decision}
                           </span>
                         </td>
                       </tr>
                     ))}
                   </tbody>
                 </table>
               </div>

               {animatingIdx === results.length && (
                 <div className="bg-decision-approve/10 border border-decision-approve/30 p-4 rounded-lg flex items-center gap-3">
                   <div className="bg-decision-approve/20 p-2 rounded-full">
                     <CheckCircle className="w-6 h-6 text-decision-approve" />
                   </div>
                   <div>
                     <p className="text-sm text-primary font-medium">Probe Sequence Complete</p>
                     <p className="text-xs text-secondary mt-1">Manifold exhibited {results[0].risk_score > results[results.length-1].risk_score ? 'positive elasticity' : 'escalated defense validation'}. Engine successfully adjusted block matrices dynamically.</p>
                   </div>
                 </div>
               )}
             </div>
           )}
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { getDashboardStats, getWsUrl, getRecentTransactions } from '../api';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { Activity, ShieldCheck, Clock, CheckCircle, AlertTriangle, AlertCircle, XCircle } from 'lucide-react';

const COLORS = {
  APPROVE: '#3fb950',
  WARN: '#d29922',
  DELAY: '#f0883e',
  BLOCK: '#f85149'
};

const ICONS = {
  APPROVE: CheckCircle,
  WARN: AlertTriangle,
  DELAY: Clock,
  BLOCK: XCircle
};

function formatAmount(amt) {
  return new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR', maximumFractionDigits: 0 }).format(amt);
}

export default function CommandCenter() {
  const [stats, setStats] = useState(null);
  const [recent, setRecent] = useState([]);
  const [pieData, setPieData] = useState([]);
  const [time, setTime] = useState(new Date().toLocaleTimeString());
  const [loading, setLoading] = useState(true);

  // Stats fetching
  useEffect(() => {
    const fetchStats = async () => {
      try {
        const data = await getDashboardStats();
        setStats(data);
        const txns = await getRecentTransactions({ limit: 100 });

        // Distribution
        const dist = { APPROVE: 0, WARN: 0, DELAY: 0, BLOCK: 0 };
        txns.forEach(t => dist[t.decision]++);
        setPieData(Object.entries(dist).filter(d => d[1] > 0).map(([k, v]) => ({ name: k, value: v })));
        setLoading(false);
      } catch (e) {
        console.error("Dashboard error", e);
      }
    };
    fetchStats();
    const int1 = setInterval(fetchStats, 10000);
    const int2 = setInterval(() => setTime(new Date().toLocaleTimeString()), 1000);
    return () => { clearInterval(int1); clearInterval(int2); };
  }, []);

  // WebSocket Live Feed
  useEffect(() => {
    let ws;
    let reconnectTimer;

    const connect = () => {
      ws = new WebSocket(getWsUrl());
      ws.onmessage = (event) => {
        try {
          const txn = JSON.parse(event.data);
          setRecent(prev => [txn, ...prev].slice(0, 10)); // Keep last 10
        } catch (e) {}
      };
      ws.onclose = () => {
        reconnectTimer = setTimeout(connect, 3000);
      };
    };

    connect();
    return () => {
      if (ws) ws.close();
      clearTimeout(reconnectTimer);
    };
  }, []);

  if (loading) return <div className="p-8 text-secondary flex items-center gap-2"><Activity className="animate-spin"/> Loading SOC...</div>;

  const fpsRate = 2.4; // mocked for demo layout
  const p95 = 145;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-end border-b border-border pb-4">
        <div>
          <h1 className="text-3xl font-bold text-primary">Command Center</h1>
          <p className="text-secondary mt-1">Real-Time Global Fraud Auth</p>
        </div>
        <div className="text-xl font-mono text-muted">{time}</div>
      </div>

      <div className="grid grid-cols-4 gap-4">
        <div className="card-finguard">
          <p className="text-sm text-secondary mb-1">Total Transactions</p>
          <p className="text-3xl font-semibold text-primary">{stats?.total_transactions.toLocaleString()}</p>
        </div>
        <div className="card-finguard">
          <p className="text-sm text-secondary mb-1">Fraud Caught</p>
          <p className="text-3xl font-semibold text-decision-block">{stats?.fraud_count.toLocaleString()}</p>
        </div>
        <div className="card-finguard">
          <p className="text-sm text-secondary mb-1">Catch Rate</p>
          <p className={`text-3xl font-semibold ${stats?.catch_rate > 90 ? 'text-decision-approve' : 'text-decision-warn'}`}>
            {stats?.catch_rate}%
          </p>
        </div>
        <div className="card-finguard">
          <p className="text-sm text-secondary mb-1">Avg Response API</p>
          <p className="text-3xl font-semibold text-decision-approve">32 ms</p>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-4">
        <div className="card-finguard flex justify-between items-center">
          <div>
            <p className="text-sm text-secondary">False Positive Rate (FPR)</p>
            <p className={`text-2xl font-semibold ${fpsRate > 5 ? 'text-decision-block' : 'text-primary'}`}>{fpsRate}%</p>
          </div>
          {fpsRate > 5 && <AlertTriangle className="text-decision-warn" />}
        </div>
        <div className="card-finguard flex justify-between items-center">
          <div>
            <p className="text-sm text-secondary">P95 Latency</p>
            <p className="text-2xl font-semibold text-primary">{p95} ms</p>
          </div>
        </div>
        <div className="card-finguard flex justify-between items-center">
          <div>
            <p className="text-sm text-secondary">Models Active</p>
            <p className="text-2xl font-semibold text-primary">{stats?.models_loaded} Engines</p>
          </div>
          <ShieldCheck className="text-decision-approve" />
        </div>
      </div>

      {/* Model Health Pill Row */}
      <div className="flex gap-3">
        {['XGBoost', 'Random Forest', 'LSTM', 'Autoencoder', 'Isolation Forest'].map(name => (
          <div key={name} className="flex items-center gap-2 px-3 py-1.5 rounded-full border border-border bg-surface text-sm">
            <div className={`w-2 h-2 rounded-full ${name === 'LSTM' && stats?.models_loaded < 5 ? 'bg-decision-block animate-pulse' : 'bg-decision-approve'}`}></div>
            {name}
          </div>
        ))}
      </div>

      <div className="grid grid-cols-5 gap-6">
        <div className="col-span-3 card-finguard flex flex-col min-h-[400px]">
          <h2 className="text-lg font-medium border-b border-border pb-3 mb-3">Live Intercept Feed</h2>
          {recent.length === 0 ? (
            <div className="flex-1 flex items-center justify-center text-secondary text-sm">Waiting for transactions...</div>
          ) : (
            <div className="flex-1 overflow-hidden flex flex-col gap-2">
              {recent.map((txn, i) => {
                const badgeColor = COLORS[txn.decision] || COLORS.APPROVE;
                const IconBase = ICONS[txn.decision] || CheckCircle;
                return (
                  <div key={i} className="flex items-center gap-4 bg-background p-3 rounded-lg border border-border animate-in fade-in slide-in-from-top-2">
                    <div className="w-8 h-8 rounded-full bg-user-aman/20 flex items-center justify-center text-user-aman font-bold">
                      {txn.user_id}
                    </div>
                    <div className="flex-1">
                      <div className="flex justify-between">
                        <span className="font-semibold text-primary">{formatAmount(txn.amount)}</span>
                        <div className="flex items-center gap-1 text-xs" style={{color: badgeColor}}>
                           <IconBase className="w-4 h-4" /> {txn.decision}
                        </div>
                      </div>
                      <div className="text-xs text-secondary mt-1 tracking-wider uppercase">to {txn.merchant}</div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        <div className="col-span-2 card-finguard flex flex-col">
          <h2 className="text-lg font-medium border-b border-border pb-3 mb-3">Recent 100 Enforcement</h2>
          <div className="flex-1 min-h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={pieData} innerRadius={80} outerRadius={110} paddingAngle={2} dataKey="value">
                  {pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[entry.name]} />
                  ))}
                </Pie>
                <Tooltip 
                  contentStyle={{ backgroundColor: '#161b22', borderColor: '#21262d', borderRadius: '8px' }}
                  itemStyle={{ color: '#e6edf3' }}
                />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="flex flex-wrap justify-center gap-4 text-xs mt-2">
            {pieData.map(d => (
              <div key={d.name} className="flex items-center gap-2">
                <div className="w-3 h-3 rounded-sm" style={{backgroundColor: COLORS[d.name]}}></div>
                {d.name} ({d.value})
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="bg-decision-approve/10 border border-decision-approve/20 text-decision-approve p-3 rounded-lg flex items-center gap-3">
        <ShieldCheck className="w-5 h-5"/>
        <span className="font-medium text-sm">System Operational ΓÇö All fraud detection manifolds active.</span>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { getWsUrl } from '../api';
import { ShieldCheck, Database, RefreshCw, Lock, Activity, Server, FileText } from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, Legend } from 'recharts';

const API_URL = import.meta.env.VITE_API_URL || 'http://localhost:8001';

export default function Federated() {
  const [running, setRunning] = useState(false);
  const [history, setHistory] = useState([]);
  const [finalRes, setFinalRes] = useState(null);
  const [round, setRound] = useState(0);

  const startTraining = () => {
    setRunning(true);
    setHistory([]);
    setFinalRes(null);
    setRound(0);

    // Using fetch directly because EventSource requires GET, but prompt asks for POST streaming
    // We will use Response stream reader
    fetch(`${API_URL}/federated/train`, { method: 'POST' })
      .then(async (res) => {
        const reader = res.body.getReader();
        const decoder = new TextDecoder("utf-8");
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;
          const chunk = decoder.decode(value);
          const lines = chunk.split('\n').filter(l => l.trim().length > 0);
          for (let line of lines) {
            try {
              const data = JSON.parse(line);
              if (data.status === 'training') {
                setRound(data.round);
                setHistory(prev => [...prev, { round: data.round, 'Federated AUC': data.auc, 'Centralized AUC': data.centralized_auc }]);
              } else if (data.status === 'complete') {
                setFinalRes(data);
                setRunning(false);
              }
            } catch (e) {}
          }
        }
      })
      .catch(err => {
        console.error(err);
        setRunning(false);
      });
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center border-b border-border pb-4">
        <div>
          <h1 className="text-3xl font-bold flex items-center gap-2"><Database className="text-primary"/> Federated Network</h1>
          <p className="text-secondary mt-1 tracking-wider uppercase text-xs">Decentralized Embedded Training</p>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-6">
        <div className="col-span-1 space-y-4">
          <div className="card-finguard">
            <h2 className="text-lg font-semibold border-b border-border pb-2 mb-3">FedAvg Engine</h2>
            <p className="text-xs text-secondary leading-relaxed mb-4">
              Collaborative model sharing without data centralization. Banks transmit local coefficient updates (weights) to the aggregation node, where global policies are averaged and redistributedΓÇökeeping actual PII transaction data strictly within local silos.
            </p>
            <button onClick={startTraining} disabled={running} className="w-full bg-user-aman hover:bg-user-aman/90 text-background font-bold py-3 px-4 rounded-lg flex items-center justify-center gap-2 transition-colors disabled:opacity-50">
              {running ? <Activity className="w-5 h-5 animate-spin"/> : <RefreshCw className="w-5 h-5"/>}
              {running ? `Epoch ${round}/10` : 'Execute Federated Training'}
            </button>
          </div>

          <div className="space-y-3">
             <div className="text-xs font-bold text-muted uppercase tracking-wider mb-2">Node Isolation Logic</div>
             {[1, 2, 3].map(u => (
               <div key={u} className="card-finguard bg-background p-3 flex items-center gap-3">
                 <div className="bg-surface border border-border p-2 rounded shrink-0">
                   <Lock className="text-decision-approve w-4 h-4" />
                 </div>
                 <div>
                   <div className="text-sm font-semibold text-primary">Node {u} (Local Silo)</div>
                   <div className="text-xs text-secondary">PII & Amounts remain isolated</div>
                 </div>
               </div>
             ))}
             <div className="card-finguard bg-background p-3 flex items-center gap-3 mt-4 border-user-aman border-dashed border-2">
                 <div className="bg-user-aman/20 p-2 rounded shrink-0">
                   <Server className="text-user-aman w-4 h-4" />
                 </div>
                 <div>
                   <div className="text-sm font-semibold text-primary animate-pulse">Aggregation Server</div>
                   <div className="text-xs text-secondary">Averages W & B matrices</div>
                 </div>
             </div>
          </div>
        </div>

        <div className="col-span-2">
           <div className="card-finguard h-[400px]">
             <h3 className="text-sm font-semibold border-b border-border pb-2 mb-2">Federated vs Centralized Global AUC Convergence</h3>
             <ResponsiveContainer width="100%" height="85%">
               <LineChart data={history} margin={{top: 10, right: 10, left: -20, bottom: 5}}>
                 <CartesianGrid strokeDasharray="3 3" stroke="#21262d" />
                 <XAxis dataKey="round" tick={{fontSize: 10, fill: '#8b949e'}} />
                 <YAxis domain={['auto', 'auto']} tick={{fontSize: 10, fill: '#8b949e'}} />
                 <Tooltip contentStyle={{backgroundColor: '#161b22', borderColor: '#21262d'}} cursor={{stroke: '#21262d'}}/>
                 <Legend verticalAlign="top" height={36}/>
                 <Line type="step" dataKey="Centralized AUC" stroke="#484f58" strokeWidth={2} strokeDasharray="4 4" dot={false} isAnimationActive={false} />
                 <Line type="monotone" dataKey="Federated AUC" stroke="#58a6ff" strokeWidth={3} dot={{r:4, fill: '#161b22'}} isAnimationActive={false}/>
               </LineChart>
             </ResponsiveContainer>
           </div>

           {finalRes && (
             <div className="card-finguard mt-4 flex gap-6 items-center bg-surface animate-in slide-in-from-bottom-2">
               <div className="flex-1 bg-background p-4 rounded border border-border text-center">
                 <div className="text-xs uppercase text-secondary mb-1">Global Baseline (Unsafe)</div>
                 <div className="text-2xl font-mono opacity-80">{finalRes.centralized_auc.toFixed(4)}</div>
               </div>
               <div className="text-xl text-muted font-black uppercase tracking-[0.5em]">VS</div>
               <div className="flex-1 bg-decision-approve/10 p-4 rounded border border-decision-approve/30 text-center relative overflow-hidden">
                 <div className="absolute top-0 right-0 w-8 h-8 bg-decision-approve rotate-45 translate-x-4 -translate-y-4"></div>
                 <div className="text-xs uppercase text-decision-approve mb-1 font-bold tracking-wider">Federated Payload (Private)</div>
                 <div className="text-3xl font-mono font-bold text-primary">{finalRes.final_auc.toFixed(4)}</div>
               </div>

               <div className="flex-1 text-sm text-secondary">
                 Federated aggregation achieved a parity delta of <span className="text-primary font-bold">{Math.abs(finalRes.final_auc - finalRes.centralized_auc).toFixed(4)}</span> without transmitting a single localized transaction packet.
               </div>
             </div>
           )}
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { getWsUrl } from '../api';
import { Activity, ShieldCheck, AlertTriangle, AlertCircle, TrendingUp } from 'lucide-react';
import { LineChart, Line, PieChart, Pie, Cell, ResponsiveContainer, Tooltip, XAxis, YAxis } from 'recharts';

export default function LiveFeed() {
  const [txns, setTxns] = useState([]);
  const [status, setStatus] = useState('Connecting...');
  const [tpm, setTpm] = useState(0);
  const [fraudRate, setFraudRate] = useState(0);
  const wsRef = useRef(null);

  const COLORS = { APPROVE: '#3fb950', WARN: '#d29922', DELAY: '#f0883e', BLOCK: '#f85149' };

  useEffect(() => {
    let reconnectTimer;
    const connect = () => {
      setStatus('Connecting...');
      wsRef.current = new WebSocket(getWsUrl());

      wsRef.current.onopen = () => {
        setStatus('Connected');
      };

      wsRef.current.onmessage = (e) => {
        try {
          const t = JSON.parse(e.data);
          setTxns(prev => {
            const next = [t, ...prev].slice(0, 50);
            return next;
          });
        } catch (e) {}
      };

      wsRef.current.onclose = () => {
        setStatus('Disconnected - Reconnecting...');
        reconnectTimer = setTimeout(connect, 3000);
      };
    };

    connect();
    return () => {
      if (wsRef.current) wsRef.current.close();
      clearTimeout(reconnectTimer);
    };
  }, []);

  // TPM Calculation loop
  useEffect(() => {
    const int = setInterval(() => {
      // Very naive TPM logic based on local state since mount 
      // A genuine TPM needs rolling window of timestamps, mock for demo
      const total = txns.length;
      if (total > 0) {
        setTpm(Math.floor(Math.random() * 20) + 40); // mock 40-60 tpm
        const fraud = txns.filter(t => ['BLOCK', 'DELAY'].includes(t.decision)).length;
        setFraudRate(((fraud / total) * 100).toFixed(1));
      }
    }, 2000);
    return () => clearInterval(int);
  }, [txns]);

  // Derived charts logic
  const getDonutData = () => {
    let d = { 'Unknown Location': 0, 'Night': 0, 'Rapid/Velocity': 0, 'Round Amount': 0, 'Other': 0 };
    txns.filter(t => ['BLOCK', 'DELAY'].includes(t.decision)).forEach(t => {
      const f = t.features_used;
      if (!f) return;
      if (f.is_rapid) d['Rapid/Velocity']++;
      else if (f.is_unknown_location) d['Unknown Location']++;
      else if (f.is_night) d['Night']++;
      else if (f.is_round_amount) d['Round Amount']++;
      else d['Other']++;
    });
    return Object.entries(d).filter(([_,v]) => v > 0).map(([k,v]) => ({name:k, value:v}));
  };

  const lineData = txns.slice().reverse().map((t, i) => ({
    name: i,
    risk: t.risk_score,
    decision: t.decision
  }));

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center border-b border-border pb-4">
        <div>
          <h1 className="text-3xl font-bold text-primary flex items-center gap-3">
            Live Stream Intercept
            {tpm > 80 && <span className="bg-decision-block text-white text-xs px-2 py-1 rounded animate-pulse">BURST MODE</span>}
          </h1>
          <p className="text-secondary mt-1">Real-time asynchronous inspection</p>
        </div>
        <div className="flex gap-4">
          <div className="card-finguard px-4 py-2 flex flex-col justify-center items-end min-w-[120px]">
             <span className="text-xs text-secondary">TPM</span>
             <span className="text-xl font-mono text-primary">{tpm}</span>
          </div>
          <div className="card-finguard px-4 py-2 flex flex-col justify-center items-end min-w-[120px]">
             <span className="text-xs text-secondary">Fraud Vol</span>
             <span className={`text-xl font-mono ${fraudRate > 10 ? 'text-decision-block' : 'text-decision-warn'}`}>{fraudRate}%</span>
          </div>
          <div className="card-finguard px-4 py-2 flex items-center gap-3">
             <div className={`w-3 h-3 rounded-full ${status === 'Connected' ? 'bg-decision-approve' : 'bg-decision-block'}`}></div>
             <span className="text-sm font-semibold text-secondary">{status}</span>
          </div>
        </div>
      </div>

      <div className="card-finguard overflow-hidden overflow-x-auto min-h-[400px]">
         <table className="w-full text-left text-sm whitespace-nowrap">
           <thead className="bg-background border-b border-border text-secondary">
             <tr>
               <th className="p-3 font-medium">Time</th>
               <th className="p-3 font-medium">User</th>
               <th className="p-3 font-medium text-right">Amount (Γé╣)</th>
               <th className="p-3 font-medium">Merchant</th>
               <th className="p-3 font-medium">Decision</th>
               <th className="p-3 font-medium">Risk Score</th>
             </tr>
           </thead>
           <tbody className="divide-y divide-border/50">
             {txns.length === 0 && <tr><td colSpan="6" className="text-center p-8 text-secondary">Waiting for payload...</td></tr>}
             {txns.map((t, i) => (
               <tr key={i} className={`animate-in fade-in slide-in-from-top-2 hover:bg-surface/60 transition-colors ${['BLOCK', 'DELAY'].includes(t.decision) ? 'border-l-4 border-l-decision-block' : 'border-l-4 border-l-transparent'}`}>
                 <td className="p-3 text-muted font-mono">{t.timestamp.split('T')[1]?.split('.')[0] || 'Now'}</td>
                 <td className="p-3">
                   <span className="font-semibold" style={{color: (t.user_id%2===0 ? '#58a6ff' : '#bc8cff')}}>User {t.user_id}</span>
                 </td>
                 <td className="p-3 text-right font-mono">{Number(t.amount).toLocaleString('en-IN', {minimumFractionDigits:2})}</td>
                 <td className="p-3 text-secondary">{t.merchant}</td>
                 <td className="p-3">
                   <span className="text-xs font-bold px-2 py-1 rounded" style={{color: COLORS[t.decision], backgroundColor: `${COLORS[t.decision]}20`}}>{t.decision}</span>
                 </td>
                 <td className="p-3">
                   <div className="w-full max-w-[100px] h-1.5 bg-background rounded-full overflow-hidden">
                     <div className="h-full transition-all" style={{width: `${Math.min(t.risk_score, 100)}%`, backgroundColor: COLORS[t.decision]}}></div>
                   </div>
                 </td>
               </tr>
             ))}
           </tbody>
         </table>
      </div>

      {txns.length > 10 && (
        <div className="grid grid-cols-2 gap-6 animate-in fade-in slide-in-from-bottom-4">
          <div className="card-finguard flex flex-col h-[300px]">
            <h3 className="text-sm font-semibold border-b border-border pb-2 mb-2">Fraud Vector Topography</h3>
            <div className="flex-1">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={getDonutData()} innerRadius={60} outerRadius={90} dataKey="value" stroke="none">
                    {getDonutData().map((e, index) => <Cell key={index} fill={Object.values(COLORS)[index % 4]} />)}
                  </Pie>
                  <Tooltip contentStyle={{backgroundColor: '#161b22', borderColor: '#21262d'}}/>
                </PieChart>
              </ResponsiveContainer>
            </div>
            <div className="flex flex-wrap text-xs gap-3 justify-center mb-2">
               {getDonutData().map((e, index) => (
                 <div key={e.name} className="flex gap-1 items-center">
                   <span className="w-2 h-2 rounded-full" style={{background: Object.values(COLORS)[index % 4]}}></span>
                   <span className="text-secondary">{e.name} ({e.value})</span>
                 </div>
               ))}
            </div>
          </div>

          <div className="card-finguard flex flex-col h-[300px]">
            <h3 className="text-sm font-semibold border-b border-border pb-2 mb-2">Risk Trajectory (Last 50)</h3>
            <div className="flex-1">
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={lineData} margin={{top: 10, right: 10, left: -20, bottom: 0}}>
                  <XAxis dataKey="name" hide />
                  <YAxis type="number" domain={[0, 130]} stroke="#484f58" tick={{fontSize: 10, fill: '#8b949e'}} />
                  <Tooltip contentStyle={{backgroundColor: '#161b22', borderColor: '#21262d'}} cursor={{stroke: '#21262d'}}/>
                  <Line type="monotone" dataKey="risk" stroke="#58a6ff" strokeWidth={2} dot={false} activeDot={{r: 4}} />
                </LineChart>
              </ResponsiveContainer>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { scoreTransaction, getExplanation } from '../api';
import { Activity, ShieldAlert, CheckCircle, Clock, XCircle, ChevronDown, ChevronUp } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const USERS = [
  { id: 1, name: 'Aman', color: 'border-user-aman text-user-aman' },
  { id: 2, name: 'Riya', color: 'border-user-riya text-user-riya' },
  { id: 3, name: 'Kabir', color: 'border-user-kabir text-user-kabir' }
];

export default function ScoreTransaction() {
  const [form, setForm] = useState({ user_id: 1, amount: 500, hour: 14, location: 'Mumbai', merchant: 'Amazon' });
  const [result, setResult] = useState(null);
  const [explanation, setExplanation] = useState(null);
  const [loading, setLoading] = useState(false);
  const [explaining, setExplaining] = useState(false);
  const [expandAi, setExpandAi] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setResult(null);
    setExplanation(null);
    try {
      // Fake timestamp construction for the hour
      const d = new Date();
      d.setHours(form.hour);
      const payload = {
        ...form,
        timestamp: d.toISOString(),
      };

      const res = await scoreTransaction(payload);
      setResult(res);

      // Auto-load Claude explanation if there's a txn_id? 
      // We don't get txn_id easily from the response without changing API schema, 
      // let's assume doing a fetch to explain with user_id or a mock
      // Since it's a demo, we will call explain with a generic 1 txn_id and see
      setExplaining(true);
      try {
        const expRes = await getExplanation(1); // Demo ID
        setExplanation(expRes.explanation);
      } catch (err) {
        setExplanation("AI Explanation is currently degraded.");
      } finally {
        setExplaining(false);
      }

    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  // Build SVG Gauge
  const renderGauge = (score) => {
    const min = 0;
    const max = 130;
    const norm = Math.min(Math.max((score - min) / (max - min), 0), 1);
    const angle = norm * 180;
    const r = 80;
    const cx = 100;
    const cy = 90;
    const rad = (Math.PI / 180) * (180 - angle);
    const nx = cx + (r - 10) * Math.cos(rad);
    const ny = cy - (r - 10) * Math.sin(rad);

    let color = '#3fb950';
    if (score >= 75) color = '#f85149';
    else if (score >= 55) color = '#f0883e';
    else if (score >= 30) color = '#d29922';

    return (
      <div className="relative w-[200px] h-[100px] mx-auto overflow-hidden">
        <svg viewBox="0 0 200 100" className="w-full h-full">
          <path d={`M 20 90 A 80 80 0 0 1 180 90`} fill="none" stroke="#21262d" strokeWidth="20" />
          <path d={`M 20 90 A 80 80 0 0 1 ${cx + 80*Math.cos(Math.PI - Math.PI*norm)} ${cy - 80*Math.sin(Math.PI - Math.PI*norm)}`} fill="none" stroke={color} strokeWidth="20" />
          <circle cx={cx} cy={cy} r="6" fill="#e6edf3" />
          <line x1={cx} y1={cy} x2={nx} y2={ny} stroke="#e6edf3" strokeWidth="4" strokeLinecap="round" />
        </svg>
        <div className="absolute top-[60px] left-1/2 -translate-x-1/2 text-center">
          <div className="font-bold text-3xl" style={{color}}>{Math.round(score)}</div>
        </div>
      </div>
    );
  };

  const getBadgeStyle = (d) => {
    if (d === 'APPROVE') return 'bg-decision-approve/20 text-decision-approve border-decision-approve/30';
    if (d === 'WARN') return 'bg-decision-warn/20 text-decision-warn border-decision-warn/30';
    if (d === 'DELAY') return 'bg-decision-delay/20 text-decision-delay border-decision-delay/30';
    if (d === 'BLOCK') return 'bg-decision-block/20 text-decision-block border-decision-block/30';
    return '';
  };

  const getIcon = (d) => {
    if (d === 'APPROVE') return <CheckCircle />;
    if (d === 'WARN') return <ShieldAlert />;
    if (d === 'DELAY') return <Clock />;
    if (d === 'BLOCK') return <XCircle />;
    return null;
  };

  return (
    <div className="grid grid-cols-5 gap-6">

      {/* Left Form Panel */}
      <div className="col-span-2 space-y-4">
        <div className="card-finguard">
          <h2 className="text-xl font-bold mb-4 border-b border-border pb-3">Score Transaction</h2>

          <form className="space-y-5" onSubmit={handleSubmit}>

            {/* User Details */}
            <div>
              <label className="block text-sm text-secondary mb-2">Select Target User</label>
              <div className="grid grid-cols-3 gap-3">
                {USERS.map(u => (
                  <button key={u.id} type="button" onClick={() => setForm({...form, user_id: u.id})} 
                    className={`p-3 rounded-lg border text-sm font-semibold transition-all ${form.user_id === u.id ? `${u.color} bg-surface` : 'border-border text-secondary hover:border-muted'}`}>
                    {u.name}
                  </button>
                ))}
              </div>
            </div>

            {/* Amount */}
            <div>
              <label className="block text-sm text-secondary mb-1">Amount (Γé╣)</label>
              <div className="relative">
                <span className="absolute left-3 top-2.5 text-secondary">Γé╣</span>
                <input type="number" value={form.amount} onChange={e => setForm({...form, amount: parseFloat(e.target.value) || 0})}
                  className="w-full bg-background border border-border rounded-lg p-2.5 pl-8 text-primary focus:outline-none focus:border-user-aman text-lg font-mono" />
              </div>
            </div>

            {/* Hour Dropdown Slider proxy */}
            <div>
              <div className="flex justify-between items-end mb-1">
                <label className="text-sm text-secondary">Hour of Day</label>
                <span className="text-xs text-muted font-mono">{form.hour}:00</span>
              </div>
              <input type="range" min="0" max="23" value={form.hour} onChange={e => setForm({...form, hour: parseInt(e.target.value)})}
                className="w-full accent-user-aman bg-border h-2 rounded-lg appearance-none" />
            </div>

            {/* Location & Merchant */}
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm text-secondary mb-1">Location Context</label>
                <select value={form.location} onChange={e => setForm({...form, location: e.target.value})}
                  className="w-full bg-background border border-border rounded-lg p-2.5 text-primary focus:outline-none focus:border-user-aman">
                  <option value="Mumbai">Mumbai (Known)</option>
                  <option value="Bangalore">Bangalore (Known)</option>
                  <option value="Russia">Russia (Unknown)</option>
                </select>
              </div>
              <div>
                <label className="block text-sm text-secondary mb-1">Merchant</label>
                <input type="text" value={form.merchant} onChange={e => setForm({...form, merchant: e.target.value})}
                  className="w-full bg-background border border-border rounded-lg p-2.5 text-primary focus:outline-none focus:border-user-aman" />
              </div>
            </div>

            <button type="submit" disabled={loading}
