                        </Bar>
                      </BarChart>
                    </ResponsiveContainer>
                 )}
               </div>
            </div>

            <div className="text-right">
              <span className="bg-background border border-border text-muted text-xs px-2 py-1 rounded-full">
                Latency: {result.latency_ms}ms
              </span>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
